def detect_parallel_conflicts(response):
    tool_results = [c for c in response.content if c.type == 'tool_result']
    if len(tool_results) < 2:
        return False

    # Check for conflicting data types in same tool name
    results_by_tool = {}
    for result in tool_results:
        tool_name = result.tool_use_id.split('_')[0]
        if tool_name not in results_by_tool:
            results_by_tool[tool_name] = []
        results_by_tool[tool_name].append(result.content[0].type)

    for tool_name, types in results_by_tool.items():
        if len(set(types)) > 1:
            return True
    return False

