const detectDivergence = (response) => {
  const reasoning = response.content.find(c => c.type === 'text')?.text || '';
  const toolInputs = response.content
    .filter(c => c.type === 'tool_use')
    .map(t => JSON.stringify(t.input));

  // Simple keyword divergence check
  const reasoningWords = new Set(reasoning.toLowerCase().split(' '));
  const toolWords = new Set(toolInputs.join(' ').toLowerCase().split(' '));

  const intersection = new Set([...reasoningWords].filter(w => toolWords.has(w)));
  const divergenceScore = intersection.size / Math.max(reasoningWords.size, 1);

  return divergenceScore < 0.3; // High divergence
};

