def safe_tool_chain(client, messages, tools):
    response = client.messages.create(model="claude-3-5-sonnet-20240620", max_tokens=1024, tools=tools, messages=messages)

    tool_uses = [c for c in response.content if c.type == 'tool_use']
    for tool_use in tool_uses:
        if 'error' in str(tool_use.input).lower():
            # Retry only this specific tool
            retry_msg = messages + [response, {"role": "user", "content": "Retry only the failed tool:"}]
            return safe_tool_chain(client, retry_msg, tools)
    return response

const arbitrateParallelTools = (toolResults) => {
  const resultsByTool = {};
  toolResults.forEach(result => {
    const toolId = result.tool_use_id;
    if (!resultsByTool[toolId]) resultsByTool[toolId] = [];
    resultsByTool[toolId].push(result.content[0]);
  });

  // Weighted vote by confidence (if available) or majority
  const arbitrated = {};
  for (const [toolId, results] of Object.entries(resultsByTool)) {
    const mostCommon = results
      .sort((a, b) => (b.confidence || 0) - (a.confidence || 0))[0];
    arbitrated[toolId] = mostCommon;
  }

  return arbitrated;
};
